func:
flow.set("step", "calculate");
msg.url = "http://localhost:8080";

// ─── Materialzusammensetzung pro Prozess ───────────────────────────────────
// Alle Mengenangaben beziehen sich auf den jeweiligen Prozess-Output (1 Stück)
// Die Skalierung auf 25 Kugelschreiber übernimmt openLCA automatisch.

const processes = [
  {
    name: "Bolzen",
    uuid: "90291baa-d449-4afc-9d2a-01e8e650afd8",
    // Output: 0.001 kg Bolzen
    // Annahme: hauptsächlich Stahl, kleiner Aluminiumanteil für Kopf
    params: {
      Menge_Stahl_Bolzen:      0.00082,  // kg – Stahlschaft
      Menge_Aluminium_Bolzen:  0.00010,  // kg – Alukopf
      Energieverbrauch_Bolzen: 0.0035    // MJ – Drehen + Gewindefräsen
    }
  },
  {
    name: "Druckfeder",
    uuid: "b3ba806e-e296-4943-8bc7-01858c5ab333",
    // Output: 0.001 kg Druckfeder
    // Annahme: reiner Federstahl, kein Verlust
    params: {
      Menge_Stahl_Druckfeder: 0.00095   // kg – Federdraht (5% Verschnitt)
    }
  },
  {
    name: "Huelse",
    uuid: "57c37380-e320-4712-b605-48dca9472829",
    // Output: 0.001 kg Hülse
    // Annahme: Alu-Hülse mit Stahlverstärkungsring
    params: {
      Menge_Stahl_Huelse:      0.00015,  // kg – Verstärkungsring
      Menge_Aluminium_Huelse:  0.00075,  // kg – Hauptkörper
      Energieverbrauch_Huelse: 0.0028    // MJ – Tiefziehen
    }
  },
  {
    name: "Mine",
    uuid: "98446bf7-e23a-454a-9e33-67cf55533b8c",
    // Output: 0.005 kg Mine
    // Annahme: Stahlröhrchen + PP-Tinte/Tintenbehälter
    params: {
      Menge_Stahl_Mine:        0.00310,  // kg – Stahlröhrchen
      Menge_Polypropylene_Mine: 0.00160  // kg – PP-Tintenbehälter
    }
  },
  {
    name: "Stiftspitze",
    uuid: "5043f2ab-9463-470d-888e-1855c805b042",
    // Output: 0.003 kg Stiftspitze
    // Annahme: PLA-Hauptkörper, ABS-Klemmring, PP-Dichtung
    params: {
      Menge_Stiftspitze_PLA:          0.00180,  // kg – Hauptkörper (PLA)
      Menge_Stiftspitze_ABS:          0.00080,  // kg – Klemmring (ABS)
      Menge_Stiftspitze_Polypropylene: 0.00025, // kg – Dichtung (PP)
      Energieverbrauch_Stiftspitze:   0.0045    // MJ – Spritzguss
    }
  },
  {
    name: "Schraube M4",
    uuid: "0b5fd7c7-29c7-446b-8ed9-8ed75b5a07ee",
    // Output: 0.001 kg Schraube
    // Annahme: Vollstahl, kein Zusatzmaterial
    params: {
      Menge_Stahl_Schraube: 0.00092    // kg – inkl. ~8% Fertigungsverlust
    }
  }
];

// ─── parameterRedefs aufbauen ──────────────────────────────────────────────
const parameterRedefs = [];
for (const proc of processes) {
  for (const [paramName, paramValue] of Object.entries(proc.params)) {
    parameterRedefs.push({
      "@type": "ParameterRedef",
      name: paramName,
      value: paramValue,
      context: {
        "@type": "Process",
        "@id": proc.uuid
      }
    });
  }
}

msg.payload = {
  jsonrpc: "2.0",
  id: 1,
  method: "result/calculate",
  params: {
    "@type": "CalculationSetup",
    target: {
      "@type": "ProductSystem",
      "@id": "78d8a79f-218d-4be9-bae4-06bca0ec5c66"
    },
    impactMethod: {
      "@type": "ImpactMethod",
      "@id": "787c02f1-d1f2-36d6-8e06-2307cc3ebebc"
    },
    amount: 25,
    parameterRedefs: parameterRedefs
  }
};
return msg;

if (msg.payload.error) {
  node.error("Calculate error: " + msg.payload.error.message, msg);
  return null;
}

const resultId = msg.payload.result?.["@id"];
if (!resultId) {
  node.error("No result ID returned: " + JSON.stringify(msg.payload), msg);
  return null;
}

flow.set("resultId", resultId);
flow.set("step", "check-state");

msg.payload = {
  jsonrpc: "2.0",
  id: 2,
  method: "result/state",
  params: { "@type": "Result", "@id": resultId }
};
return msg;

if (msg.payload.error) {
  node.error("State error: " + msg.payload.error.message, msg);
  return null;
}

const state = msg.payload.result;
const resultId = flow.get("resultId");

if (state?.isReady === true) {
  flow.set("step", "get-impacts");
  msg.payload = {
    jsonrpc: "2.0",
    id: 3,
    method: "result/total-impacts",
    params: { "@type": "Result", "@id": resultId }
  };
  return [msg, null];
} else {
  flow.set("step", "check-state");
  msg.payload = {
    jsonrpc: "2.0",
    id: 2,
    method: "result/state",
    params: { "@type": "Result", "@id": resultId }
  };
  return [null, msg];
}

if (msg.payload.error) {
  node.error("Impacts error: " + msg.payload.error.message, msg);
  return null;
}

const GWP_CATEGORY_ID = "0529022f-23cd-36e5-bbba-3aff792d439c";
const impacts = msg.payload.result ?? [];

const gwp = impacts.find(r =>
  r.impactCategory?.["@id"] === GWP_CATEGORY_ID
);

flow.set("pcfResult", {
  processName:      "LCA Prozess: Kugelschreiber TRACEpen",
  processUUID:      "78d8a79f-218d-4be9-bae4-06bca0ec5c66",
  impactMethod:     "IPCC 2013 GWP 100a",
  targetOutput:     "25 Stück",
  totalPCF_kgCO2eq: gwp ? +gwp.amount.toFixed(6) : null,
  unit:             "kg CO2 eq",
  allImpacts:       impacts.map(r => ({
    category: r.impactCategory?.name,
    value:    r.amount,
    unit:     r.impactCategory?.refUnit
  })),
  calculatedAt: new Date().toISOString()
});

flow.set("step", "dispose");
msg.payload = {
  jsonrpc: "2.0",
  id: 4,
  method: "result/dispose",
  params: { "@type": "Result", "@id": flow.get("resultId") }
};
return msg;
